def get_jwks():
    """Fetches and caches the JWKS (JSON Web Key Set) from the OIDC provider."""
    # In a real application, you would implement proper caching with expiry
    if 'jwks' not in app.config:
        response = requests.get(JWKS_URI)
        response.raise_for_status()
        app.config['jwks'] = response.json()
    return app.config['jwks']

