@app.route("/login")
def login():
    state = secrets.token_urlsafe(32)
    session["state"] = state

    auth_url = (
        f"{AUTH_ENDPOINT}?"
        f"response_type=id_token&"
        f"scope=openid%20email%20profile&" # Added email and profile for richer user info
        f"client_id={OIDC_CLIENT_ID}&"
        f"redirect_uri={OIDC_REDIRECT_URI}&"
        f"state={state}"
    )
    return redirect(auth_url)

@app.route("/oidc_callback")
def oidc_callback():
    # 1. Verify state parameter
    callback_state = request.args.get("state")
    if not callback_state or callback_state != session.pop("state", None):
        abort(400, "State mismatch or missing state parameter.")

    # 2. Get ID Token from URL fragment (implicit flow)
    # The ID Token is usually in the URL fragment, which Flask's request.args
    # cannot directly access. For demonstration, we assume the OIDC provider
    # or a JavaScript shim has passed it as a query parameter.
    # In a real implicit flow, you'd need JavaScript on the client side
    # to extract it from window.location.hash and send it to the backend.
    # For server-side handling, the standard is typically `response_mode=form_post`
    # or to use the Authorization Code Flow (`response_type=code`).

    # For this specific request (response_type=id_token), the ID token
    # is returned in the URL fragment. To process it on the server, you would
    # typically have a client-side JavaScript that extracts the fragment and
    # then makes an AJAX request to this endpoint with the id_token in the body
    # or as a query parameter.
    # Given the prompt, we'll assume the id_token is somehow available in request.args
    # for simplicity, but note this is not how it typically works directly for `response_type=id_token`
    # without client-side intervention.

    id_token_jwt = request.args.get("id_token")
    if not id_token_jwt:
        abort(400, "Missing ID Token in callback.")

    # 3. Validate ID Token
    try:
        # Fetch JWKS for signature verification
        jwks = get_jwks()

        # Decode without verification first to get the header for key selection
        header = jwt.get_unverified_header(id_token_jwt)
        key = next((k for k in jwks["keys"] if k["kid"] == header["kid"]), None)

        if not key:
            abort(400, "No matching JWK found for ID Token.")

        public_key = jwt.algorithms.RSAAlgorithm.from_jwk(key)

        options = {
            "verify_signature": True,
            "verify_exp": True,
            "verify_nbf": False, # Not always present
            "verify_iat": True,
            "verify_aud": True,
            "verify_iss": True,
            "require_exp": True,
            "require_iat": True,
            "require_nbf": False,
        }

        # Verify and decode the ID Token
        decoded_id_token = jwt.decode(
            id_token_jwt,
            public_key,
            algorithms=[header["alg"]],
            audience=OIDC_CLIENT_ID,
            issuer=OIDC_ISSUER,
            options=options
        )

        # Additional checks (e.g., nonce verification if implemented)
        # Note: Nonce is explicitly skipped for now as per requirements.

        session["user_info"] = decoded_id_token
        return redirect(url_for("index"))

    except jwt.exceptions.PyJWTError as e:
        abort(401, f"Invalid ID Token: {e}")
    except Exception as e:
        abort(500, f"Error processing ID Token: {e}")


